// Package gitlock provides recovery helpers for transient .git/index.lock
// contention. It is shared by the agent execute-loop and the bead
// auto-commit path so both benefit from identical recovery semantics.
package gitlock

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// StaleAge is the age after which a .git/index.lock with no identifiable live
// owner is considered stale and safe to remove.
//
// All DDx writers serialize through withMainGitLock (.ddx/.git-tracker.lock),
// so an unowned index.lock past this threshold represents either a crashed git
// process or an operator command that exited without cleanup.
var StaleAge = 30 * time.Second

// RecoveryAttempts bounds the total number of attempts (including the initial
// try) made by RunGitWithIndexLockRecovery.
const RecoveryAttempts = 3

// LiveOwnerWait is the wait between retries when a live process holds the lock.
// Short by design: stalling is not acceptable here.
var LiveOwnerWait = 500 * time.Millisecond

// IsIndexLockError reports whether the git output is the .git/index.lock-exists error.
func IsIndexLockError(output string) bool {
	lower := strings.ToLower(output)
	return strings.Contains(lower, "index.lock") &&
		(strings.Contains(lower, "file exists") || strings.Contains(lower, "another git process"))
}

// IndexLockPath returns the absolute path to .git/index.lock for projectRoot.
func IndexLockPath(projectRoot string) string {
	return filepath.Join(projectRoot, ".git", "index.lock")
}

// findGitRoot walks up from dir to find the directory that contains a .git
// entry. Returns dir unchanged if .git cannot be found (graceful fallback).
func findGitRoot(dir string) string {
	current := dir
	for {
		if _, err := os.Stat(filepath.Join(current, ".git")); err == nil {
			return current
		}
		parent := filepath.Dir(current)
		if parent == current {
			return dir
		}
		current = parent
	}
}

// IndexLockOwner attempts to identify the pid that currently holds lockPath
// open. Uses lsof if available on PATH. Returns (0, nil) if no owner can be
// determined. Failure to identify is not itself an error.
func IndexLockOwner(lockPath string) (int, error) {
	lsof, err := exec.LookPath("lsof")
	if err != nil {
		return 0, nil
	}
	out, err := exec.Command(lsof, "-t", "--", lockPath).Output()
	if err != nil {
		// lsof exits non-zero when no process has the file open.
		return 0, nil
	}
	s := strings.TrimSpace(string(out))
	if s == "" {
		return 0, nil
	}
	first := strings.SplitN(s, "\n", 2)[0]
	pid, perr := strconv.Atoi(strings.TrimSpace(first))
	if perr != nil {
		return 0, nil
	}
	return pid, nil
}

// IndexLockRecoveryResult describes the outcome of one recovery attempt
// against .git/index.lock.
type IndexLockRecoveryResult struct {
	// Removed is true if the lock file was deleted.
	Removed bool
	// OwnerPID is the pid identified as holding the lock, or 0 if unknown.
	OwnerPID int
	// OwnerAlive reports the liveness of OwnerPID at inspection time.
	// Meaningful only when OwnerPID != 0.
	OwnerAlive bool
	// Age is the lock-file age at inspection (zero if lock was missing).
	Age time.Duration
	// Reason is a human-readable summary suitable for log output.
	Reason string
}

// RecoverGitIndexLock inspects .git/index.lock under projectRoot. If the lock
// has no live owner — either lsof identifies a dead pid, or no pid holds it
// and the mtime is past StaleAge — the lock is removed. Otherwise the lock is
// left in place and the result describes the live owner.
//
// projectRoot may be a subdirectory of the git repo; RecoverGitIndexLock
// walks up to find the actual .git directory so callers that operate on
// subdirectories (e.g. .ddx/) still find the correct lock file.
func RecoverGitIndexLock(projectRoot string) (IndexLockRecoveryResult, error) {
	projectRoot = findGitRoot(projectRoot)
	lockPath := IndexLockPath(projectRoot)
	info, statErr := os.Lstat(lockPath)
	if statErr != nil {
		if os.IsNotExist(statErr) {
			return IndexLockRecoveryResult{Reason: "lock not present"}, nil
		}
		return IndexLockRecoveryResult{}, fmt.Errorf("stat %s: %w", lockPath, statErr)
	}
	age := time.Since(info.ModTime())
	pid, _ := IndexLockOwner(lockPath)

	if pid > 0 {
		alive := processAlive(pid)
		if !alive {
			if rmErr := os.Remove(lockPath); rmErr != nil && !os.IsNotExist(rmErr) {
				return IndexLockRecoveryResult{OwnerPID: pid, Age: age},
					fmt.Errorf("remove lock owned by dead pid %d: %w", pid, rmErr)
			}
			return IndexLockRecoveryResult{
				Removed: true, OwnerPID: pid, OwnerAlive: false, Age: age,
				Reason: fmt.Sprintf("removed: owner pid %d not alive (lock age %s)", pid, age.Round(time.Second)),
			}, nil
		}
		return IndexLockRecoveryResult{
			OwnerPID: pid, OwnerAlive: true, Age: age,
			Reason: fmt.Sprintf("live owner pid %d (lock age %s)", pid, age.Round(time.Second)),
		}, nil
	}

	if age >= StaleAge {
		if rmErr := os.Remove(lockPath); rmErr != nil && !os.IsNotExist(rmErr) {
			return IndexLockRecoveryResult{Age: age},
				fmt.Errorf("remove unowned stale lock (age %s): %w", age, rmErr)
		}
		return IndexLockRecoveryResult{
			Removed: true, Age: age,
			Reason: fmt.Sprintf("removed: no owner found, age %s >= stale threshold %s",
				age.Round(time.Second), StaleAge),
		}, nil
	}

	return IndexLockRecoveryResult{
		Age:    age,
		Reason: fmt.Sprintf("no owner found but lock is fresh (age %s < %s)", age.Round(time.Second), StaleAge),
	}, nil
}

// RunGitWithIndexLockRecovery runs `git args...` in dir and, on
// .git/index.lock contention, identifies the owner and either removes a stale
// lock or briefly waits for a live owner before retrying.
//
// Total attempts are bounded by RecoveryAttempts; the final error is decorated
// with the most recent recovery diagnostic. The helper deliberately does NOT
// loop for tens of seconds — stalling is not acceptable here.
func RunGitWithIndexLockRecovery(ctx context.Context, dir string, args ...string) ([]byte, error) {
	var lastOut []byte
	var lastErr error
	var lastDiag string
	for attempt := 0; attempt < RecoveryAttempts; attempt++ {
		out, err := internalgit.Command(ctx, dir, args...).CombinedOutput()
		if err == nil {
			return out, nil
		}
		if !IsIndexLockError(string(out)) {
			return out, err
		}
		lastOut = out
		lastErr = err
		result, recErr := RecoverGitIndexLock(dir)
		if recErr != nil {
			return out, fmt.Errorf("%s; index-lock recovery failed: %w", strings.TrimSpace(string(out)), recErr)
		}
		lastDiag = result.Reason
		if !result.Removed {
			time.Sleep(LiveOwnerWait)
		}
	}
	if lastDiag == "" {
		return lastOut, lastErr
	}
	return lastOut, fmt.Errorf("%s; index-lock owner: %s: %w",
		strings.TrimSpace(string(lastOut)), lastDiag, lastErr)
}

package agent

import (
	"fmt"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// LockRetryPolicy describes the retry/backoff curve used when attempting to
// acquire a process-shared lock that guards git index operations on the
// primary .git (the tracker-commit lock). The policy is owned by this
// package per ddx-da11a34a AC#4: callers in cli/internal/triage and
// elsewhere consult ActionRetryWithBackoff but do not duplicate the curve
// implementation here.
//
// The curve is exponential with a cap and a bounded max-retries budget so
// that lock contention is absorbed silently up to a point, after which it
// surfaces as an ordinary error to the caller. Per TD-031 §8.5
// (LockContentionContract) lock contention does NOT change persisted bead
// status; the bead remains claimable and the worker remains `draining`.
type LockRetryPolicy struct {
	// InitialBackoff is the wait before the second attempt.
	InitialBackoff time.Duration
	// MaxBackoff caps the per-step backoff after exponential growth.
	MaxBackoff time.Duration
	// Multiplier is the per-step growth factor (>= 1.0).
	Multiplier float64
	// MaxRetries bounds the number of acquisition attempts after the
	// initial try. Total attempts = MaxRetries + 1.
	MaxRetries int
	// MaxElapsed bounds the total wall-clock time spent retrying. If both
	// MaxRetries and MaxElapsed are set, the first to trip wins.
	MaxElapsed time.Duration
}

// DefaultLockRetryPolicy returns the policy used by withTrackerLock. The
// curve is intentionally tight (sub-second) for in-process tracker-commit
// contention; the larger 30s/90s/300s curve referenced by the auto-triage
// child of ddx-3c154349 lives one layer up, in cli/internal/triage —
// it consults ActionRetryWithBackoff and re-queues across drain passes,
// while this policy resolves contention within a single attempt.
func DefaultLockRetryPolicy() LockRetryPolicy {
	return LockRetryPolicy{
		InitialBackoff: 50 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     30 * time.Second,
	}
}

// step returns the backoff duration for retry index n (0-based: n=0 is the
// wait BEFORE the second acquisition attempt).
func (p LockRetryPolicy) step(n int) time.Duration {
	if p.InitialBackoff <= 0 {
		return 0
	}
	d := float64(p.InitialBackoff)
	m := p.Multiplier
	if m < 1 {
		m = 1
	}
	for i := 0; i < n; i++ {
		d *= m
		if p.MaxBackoff > 0 && d >= float64(p.MaxBackoff) {
			d = float64(p.MaxBackoff)
			break
		}
	}
	out := time.Duration(d)
	if p.MaxBackoff > 0 && out > p.MaxBackoff {
		out = p.MaxBackoff
	}
	return out
}

// trackerLockStaleAge is the age after which a held tracker lock is
// considered stale (owner crashed mid-commit) and may be forcibly broken.
var trackerLockStaleAge = 10 * time.Minute

// trackerLockPolicy is the active retry policy for withTrackerLock.
// Tests may swap this out via the exported helpers below.
var trackerLockPolicy = DefaultLockRetryPolicy()

// trackerLockPath returns the main-git lock directory for the given project
// root. The historical name remains because tests and older comments refer to
// the tracker lock, but the lock now protects all primary-checkout git writes:
// tracker commits, pre-dispatch checkpoint/ref updates, and landing.
func trackerLockPath(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, ".git-tracker.lock")
}

// withMainGitLock acquires the process-shared main-git lock for the
// given project root, runs fn, and releases the lock. The lock is a
// directory created via os.Mkdir (atomic across processes on POSIX and
// Windows) following the same pattern as cli/internal/bead/lock.go.
//
// Contention is handled per LockRetryPolicy: exponential backoff up to a
// bounded budget. Per TD-031 §8.5 the contention itself does not change
// bead status; on budget exhaustion the caller surfaces an ordinary
// execution_failed and triage decides next steps.
func withMainGitLock(projectRoot string, fn func() error) error {
	if projectRoot == "" {
		return fn()
	}
	return withTrackerLockPolicy(projectRoot, trackerLockPolicy, fn)
}

// WithMainGitLock exposes the process-shared main-git lock to sibling
// packages that need the same serialized add/commit boundary as execute-bead
// landing and pre-dispatch checkpointing.
func WithMainGitLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// withTrackerLock is retained for existing tracker/pre-dispatch call sites. It
// uses the same process-shared lock as landing so separate ddx work processes
// cannot interleave commits, ref updates, and checkout sync in the main tree.
func withTrackerLock(projectRoot string, fn func() error) error {
	return withMainGitLock(projectRoot, fn)
}

// TrackerLockSample carries timing and contention metrics for one
// withTrackerLock / withMainGitLock acquire+release cycle.
type TrackerLockSample struct {
	LockDir string
	Wait    time.Duration // time from entry to lock acquisition
	Hold    time.Duration // time the callback held the lock
	Retries int           // number of sleep-and-retry iterations (0 = acquired on first try)
}

// TrackerLockMetricsSink is called after each successful tracker-lock
// acquire+release cycle. The zero value (nil) is a no-op. Tests may swap
// this to capture metrics.
var TrackerLockMetricsSink func(TrackerLockSample)

// withTrackerLockPolicy is the policy-parameterised form of
// withTrackerLock; exposed at package scope so tests can pin a specific
// curve.
func withTrackerLockPolicy(projectRoot string, policy LockRetryPolicy, fn func() error) error {
	lockDir := trackerLockPath(projectRoot)
	if err := os.MkdirAll(filepath.Dir(lockDir), 0o755); err != nil {
		return fmt.Errorf("tracker lock dir: %w", err)
	}

	start := time.Now()
	retries := 0
	for attempt := 0; ; attempt++ {
		err := os.Mkdir(lockDir, 0o755)
		if err == nil {
			_ = os.WriteFile(filepath.Join(lockDir, "pid"),
				[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
			_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
				[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
			break
		}

		// Classify what exists at lockDir before deciding to sleep or fail.
		// Per TD-031 §8.5: only a confirmed lock directory enters retry/backoff;
		// malformed paths are operator diagnostics, not lock contention.
		info, statErr := os.Lstat(lockDir)
		if statErr != nil {
			if os.IsNotExist(statErr) {
				// Path disappeared between Mkdir and Lstat (race). Retry immediately.
				continue
			}
			return fmt.Errorf("tracker lock stat: %w", statErr)
		}

		switch {
		case info.Mode().IsDir():
			// Real lock directory. Apply existing stale-owner policy.
			if breakStaleTrackerLock(lockDir) {
				continue
			}
			if attempt >= policy.MaxRetries {
				return lockTimeoutError(lockDir, "max retries")
			}
			if policy.MaxElapsed > 0 && time.Since(start) >= policy.MaxElapsed {
				return lockTimeoutError(lockDir, "max elapsed")
			}
			retries++
			time.Sleep(policy.step(attempt))

		case info.Mode().IsRegular():
			// Malformed: lock path must be a directory, not a regular file.
			if time.Since(info.ModTime()) > trackerLockStaleAge {
				// Stale regular file: remove with single-path removal and retry immediately.
				if rmErr := os.Remove(lockDir); rmErr != nil && !os.IsNotExist(rmErr) {
					return fmt.Errorf("tracker lock: remove malformed stale file %s: %w", lockDir, rmErr)
				}
				continue
			}
			return fmt.Errorf("tracker lock: malformed lock path %s is a regular file; a lock directory was expected — remove it manually to recover", lockDir)

		default:
			// Symlink, socket, device, or other special filesystem object. Do not remove.
			return fmt.Errorf("tracker lock: malformed lock path %s has type %v; a lock directory was expected — inspect and remove it manually to recover", lockDir, info.Mode().Type())
		}
	}

	waitDur := time.Since(start)
	holdStart := time.Now()
	defer os.RemoveAll(lockDir)
	fnErr := fn()
	if sink := TrackerLockMetricsSink; sink != nil {
		sink(TrackerLockSample{LockDir: lockDir, Wait: waitDur, Hold: time.Since(holdStart), Retries: retries})
	}
	return fnErr
}

func lockTimeoutError(lockDir, why string) error {
	owner := "missing"
	if pidData, perr := os.ReadFile(filepath.Join(lockDir, "pid")); perr == nil && len(pidData) > 0 {
		owner = strings.TrimSpace(string(pidData))
	}
	return fmt.Errorf("tracker lock timeout (%s, lock: %s, owner pid: %s)", why, lockDir, owner)
}

// breakStaleTrackerLock removes lockDir if its owner process is dead or the
// lock is older than trackerLockStaleAge. Returns true if the lock was broken.
func breakStaleTrackerLock(lockDir string) bool {
	pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
	if err == nil {
		pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
		if err == nil && pid > 0 && pid != os.Getpid() {
			if !trackerProcessAlive(pid) {
				os.RemoveAll(lockDir)
				return true
			}
		}
	}

	acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
	if err == nil {
		acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
		if err == nil && time.Since(acquired) > trackerLockStaleAge {
			os.RemoveAll(lockDir)
			return true
		}
	}

	return false
}

package agent

import (
	"bytes"
	"context"
	"crypto/rand"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"encoding/xml"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"errors"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	agentlib "github.com/easel/fizeau"
)

// ExecuteBeadResult captures the outcome of an execute-bead worker run.
// The worker populates the task-level fields (BeadID through UsageFile).
// The parent orchestrator (LandBeadResult) populates the landing fields
// (Outcome, Status, Detail, Reason, PreserveRef, GateResults, RequiredExecSummary,
// ChecksFile) via ApplyLandingToResult before the result is written to disk or
// returned to a caller.
type ExecuteBeadResult struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	BaseRev   string `json:"base_rev"`
	ResultRev string `json:"result_rev,omitempty"`
	// ImplementationRev is the worker's own commit SHA — the candidate revision
	// produced by the agent before landing. Set from ResultRev by
	// ApplyLandResultToExecuteBeadResult before ResultRev is rewritten to the
	// branch tip. Never overwritten after first assignment.
	ImplementationRev string `json:"implementation_rev,omitempty"`
	// LandedRev is the target branch tip after the coordinator fast-forwards or
	// merges the implementation commit. Populated by ApplyLandResultToExecuteBeadResult.
	LandedRev string `json:"landed_rev,omitempty"`
	// TargetBranch is the resolved branch that received the landing. It uses the
	// landed_branch JSON name because callers care about the post-land location.
	TargetBranch string `json:"landed_branch,omitempty"`
	// EvidenceRev is the SHA of the trailing evidence commit when it differs from
	// ImplementationRev. Populated by the evidence committer; empty otherwise.
	EvidenceRev string `json:"evidence_rev,omitempty"`

	// Outcome and Status are initially set by the worker to task-level values
	// (task_succeeded / task_failed / task_no_changes), then overwritten by
	// ApplyLandingToResult with the landing decision (merged / preserved /
	// no-changes) so callers see a unified record.
	Outcome string `json:"outcome"`
	Status  string `json:"status,omitempty"`
	Detail  string `json:"detail,omitempty"`
	// OrchestratorStatus is populated after the landing/pre-merge orchestration
	// decision so result.json can distinguish worker success from final
	// non-landing outcomes.
	OrchestratorStatus string `json:"orchestrator_status,omitempty"`

	// Landing fields — populated by ApplyLandingToResult, not by ExecuteBead.
	Reason      string `json:"reason,omitempty"`
	PreserveRef string `json:"preserve_ref,omitempty"`
	// CandidateRef is the project-root git ref pinned before checks and review.
	// Format: refs/ddx/iterations/<attempt-id>/<cycle-index>.
	CandidateRef string `json:"candidate_ref,omitempty"`
	// CycleIndex is the zero-based repair-cycle index for this candidate.
	CycleIndex          int               `json:"cycle_index,omitempty"`
	GateResults         []GateCheckResult `json:"gate_results,omitempty"`
	RequiredExecSummary string            `json:"required_exec_summary,omitempty"`
	ChecksFile          string            `json:"checks_file,omitempty"`
	// Ratchet fields — populated by ApplyLandingToResult when declarative
	// ratchet thresholds were evaluated during landing. HELIX and other
	// consumers use these to distinguish ratchet-preserved attempts from
	// generic execution failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`

	// NoChangesRationale is populated when the agent wrote a rationale file to
	// the execution bundle dir inside the worktree. It carries the agent's
	// explanation of why no commits were made, and is preserved even when a
	// mixed commit + no_changes rationale is rejected.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`

	// NoEvidencePaths names worktree paths that remained dirty when the agent
	// exited without creating a commit or no_changes_rationale.txt. It helps
	// operators diagnose silent commit failures before the worktree is cleaned up.
	NoEvidencePaths []string `json:"no_evidence_paths,omitempty"`

	// CycleTrace records the append-only execution cycle trace in order.
	// Each entry captures one implementation or repair cycle.
	CycleTrace []ExecutionCycleTrace `json:"cycle_trace,omitempty"`

	// ResourceExhausted captures the root and cleanup summary when execution
	// stopped before a bead attempt because the host could not safely continue.
	ResourceExhausted any `json:"resource_exhausted,omitempty"`

	Harness                     string  `json:"harness,omitempty"`
	Provider                    string  `json:"provider,omitempty"`
	Model                       string  `json:"model,omitempty"`
	ActualPower                 int     `json:"actual_power,omitempty"`
	PredictedPower              int     `json:"predicted_power,omitempty"`
	PredictedSpeedTPS           float64 `json:"predicted_speed_tps,omitempty"`
	PredictedCostUSDPer1kTokens float64 `json:"predicted_cost_usd_per_1k_tokens,omitempty"`
	PredictedCostSource         string  `json:"predicted_cost_source,omitempty"`
	SessionID                   string  `json:"session_id,omitempty"`
	DurationMS                  int     `json:"duration_ms"`
	Tokens                      int     `json:"tokens,omitempty"`
	CostUSD                     float64 `json:"cost_usd,omitempty"`
	ExitCode                    int     `json:"exit_code"`
	Error                       string  `json:"error,omitempty"`
	ProjectRoot                 string  `json:"project_root,omitempty"`

	// FailureMode classifies why an execution did not land cleanly. Empty
	// when the bead was merged (task_succeeded landing outcome). Populated
	// by the orchestrator from known patterns; see ClassifyFailureMode and
	// the FailureMode* constants in execute_bead_status.go.
	FailureMode string `json:"failure_mode,omitempty"`

	ExecutionDir       string             `json:"execution_dir,omitempty"`
	PromptFile         string             `json:"prompt_file,omitempty"`
	ManifestFile       string             `json:"manifest_file,omitempty"`
	ResultFile         string             `json:"result_file,omitempty"`
	UsageFile          string             `json:"usage_file,omitempty"`
	WorktreePath       string             `json:"worktree_path,omitempty"`
	AttemptDiagnostics *AttemptDiagnostic `json:"attempt_diagnostics,omitempty"`
	Stderr             string             `json:"stderr,omitempty"`
	RateLimitBudget    time.Duration      `json:"rate_limit_budget,omitempty"`

	StartedAt  time.Time `json:"started_at"`
	FinishedAt time.Time `json:"finished_at"`
}

// ExecutionCycleRouteFacts captures the implementer-side routing facts for
// one execution cycle.
type ExecutionCycleRouteFacts struct {
	Harness         string `json:"harness,omitempty"`
	Provider        string `json:"provider,omitempty"`
	Model           string `json:"model,omitempty"`
	ActualPower     int    `json:"actual_power,omitempty"`
	RouteReason     string `json:"route_reason,omitempty"`
	ResolvedBaseURL string `json:"resolved_base_url,omitempty"`
}

// ExecutionCycleReviewResult captures the reduced review outcome for one
// execution cycle.
type ExecutionCycleReviewResult struct {
	Verdict        string     `json:"verdict,omitempty"`
	Rationale      string     `json:"rationale,omitempty"`
	Classification string     `json:"classification,omitempty"`
	PerAC          []ReviewAC `json:"per_ac,omitempty"`
	Findings       []Finding  `json:"findings,omitempty"`
}

// ExecutionCycleTrace records one implementation or repair cycle and its
// durable review/final-decision metadata.
type ExecutionCycleTrace struct {
	CycleIndex       int                        `json:"cycle_index"`
	AttemptID        string                     `json:"attempt_id,omitempty"`
	ResultRev        string                     `json:"result_rev,omitempty"`
	ImplementerRoute ExecutionCycleRouteFacts   `json:"implementer_route"`
	ReviewGroupID    string                     `json:"review_group_id,omitempty"`
	ReviewerIndices  []int                      `json:"reviewer_indices,omitempty"`
	ReviewVerdicts   []string                   `json:"review_verdicts,omitempty"`
	ReviewResult     ExecutionCycleReviewResult `json:"review_result,omitempty"`
	FinalDecision    string                     `json:"final_decision,omitempty"`
}

// AttemptDiagnostic captures infrastructure state when an attempt cannot be
// inspected normally. It is intentionally small and JSON-native so result.json
// remains useful even when the worker worktree has already vanished.
type AttemptDiagnostic struct {
	BeadID                 string    `json:"bead_id"`
	AttemptID              string    `json:"attempt_id"`
	WorktreePath           string    `json:"worktree_path"`
	HeadRevError           string    `json:"head_rev_error,omitempty"`
	WorktreePathExists     bool      `json:"worktree_path_exists"`
	CleanupMetadataPresent bool      `json:"cleanup_metadata_present"`
	RunStatePresent        bool      `json:"run_state_present"`
	RunState               *RunState `json:"run_state,omitempty"`
	GitWorktreeRegistered  bool      `json:"git_worktree_registered"`
}

// BeadEventAppender records append-only evidence events on a bead.
// Implemented by *bead.Store — kept as a minimal interface so the agent
